INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('land-agent-moex-00136', 'land-agent', 'land-agent-moex-107-9a386a01', 'sub-land-agent-05', NULL, 'single_choice', '「夫強秦之暴亟矣，今悉兵以臨趙，趙必亡。趙，魏之障也；趙亡，則魏且為之後。趙、 魏，又楚、燕、齊諸國之障也；趙、魏亡，則楚、燕、齊諸國為之後。」（唐順之〈信 陵君救趙論〉） 本文意旨與下列選項最相近的是：', '["血流漂杵", "所向披靡", "以鄰為壑", "脣亡齒寒"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:15+00:00", "source_pdf_sha1": "b69e8e076c7c", "answer_pdf_sha1": "15960b581ada", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "201", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "land", "db_exam_id": "land-agent"}'::jsonb, NULL),
  ('land-agent-moex-00137', 'land-agent', 'land-agent-moex-107-9a386a01', 'sub-land-agent-05', NULL, 'single_choice', '鄭子產有疾，謂子大叔曰：「我死，子必為政，唯有德者，能以寬服民，其次莫如猛。 夫火烈，民望而畏之，故鮮死焉；水懦弱，民狎而翫之，則多死焉。故寬難。」疾數月 而卒。大叔為政，不忍猛而寬。鄭國多盜，取人於萑苻之澤。大叔悔之，曰：「吾早從 夫子，不及此。」興徒兵以攻萑苻之盜，盡殺之，盜少止。仲尼曰：「善哉！政寬則民 慢，慢則糾之以猛。猛則民殘，殘則施之以寬。寬以濟猛；猛以濟寬，政是以和。」 依據上文，仲尼對為政寬猛的看法，說明最適當的是：', '["民有蹈水火而死者，未見蹈仁而死者", "政事剛柔相濟，巧拙運用，存乎一心", "賢智未足以服眾，而權勢足以屈賢者", "亂世宜強化人治，嚴刑峻法經緯人民"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:15+00:00", "source_pdf_sha1": "b69e8e076c7c", "answer_pdf_sha1": "15960b581ada", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "201", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "land", "db_exam_id": "land-agent"}'::jsonb, NULL),
  ('land-agent-moex-00138', 'land-agent', 'land-agent-moex-107-9a386a01', 'sub-land-agent-05', NULL, 'single_choice', '上蔡先生云：「透得名利關，方是小歇處。今之士大夫何足道，真能言之鸚鵡也。」朱 文公曰：「今時秀才，教他說廉，直是會說廉，教他說義，直是會說義，及到做來，只 是不廉不義。」此即所謂能言鸚鵡也。夫下以言語為學，上以言語為治，世道之所以日 降也。（羅大經《鶴林玉露》） 依據上文，作者認為世道日降的原因是：', '["為政者爭奪權勢，不廉不義，讀書人亦上行下效", "為政者尸位素餐，讀書人沒有主見，唯聽命行事", "為政者與讀書人只會滿嘴廉與義，卻無相應行為", "為政者與讀書人皆譁眾取寵，好議論卻口是心非"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:15+00:00", "source_pdf_sha1": "b69e8e076c7c", "answer_pdf_sha1": "15960b581ada", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "201", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "land", "db_exam_id": "land-agent"}'::jsonb, NULL),
  ('land-agent-moex-00139', 'land-agent', 'land-agent-moex-107-9a386a01', 'sub-land-agent-05', NULL, 'single_choice', '桓南郡（桓玄）好獵，每田狩，車騎甚盛。五、六十里中，旌旗蔽隰，騁良馬，馳擊若 飛，雙甄所指，不避陵壑。或行陳不整，麏兔騰逸，參佐無不被繫束。桓道恭，玄之族 也，時為賊曹參軍，頗敢直言，常自帶絳綿繩箸腰中。玄問「此何為？」答曰：「公獵， 好縛人士；會當被縛，手不能堪芒也。」玄自此小差。 依據上文，下列選項何者最能形容桓道恭的言行表現？', '["據理力爭，不達目的誓不甘休", "委婉進諫，讓人意識到他自己的錯誤", "善用巧妙的比喻，以此引發他人的想像", "適時表現身體不適，讓他人有發問的動機"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:15+00:00", "source_pdf_sha1": "b69e8e076c7c", "answer_pdf_sha1": "15960b581ada", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "201", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "land", "db_exam_id": "land-agent"}'::jsonb, NULL),
  ('land-agent-moex-00140', 'land-agent', 'land-agent-moex-107-9a386a01', 'sub-land-agent-05', NULL, 'single_choice', '「父親去世以後，我替他整理東西，有一件老棉襖，我想扔了，我媽媽不肯，她拿去， 把它洗乾淨，從裏子上剪下一小塊，縫在她衣服的胸口部位。她做這些事，一句話也沒 說，我默默看她做，也一句話沒說，可是那感覺非常好。」 文中母親縫衣代表何種意義？', '["惜福愛物的美德", "物是人非的感慨", "難言的舐犢之情", "無盡的愛與思念"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:15+00:00", "source_pdf_sha1": "b69e8e076c7c", "answer_pdf_sha1": "15960b581ada", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "201", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "land", "db_exam_id": "land-agent"}'::jsonb, NULL),
  ('land-agent-moex-00141', 'land-agent', 'land-agent-moex-107-9a386a01', 'sub-land-agent-05', NULL, 'single_choice', '一個人要吃得像動物一樣簡單，是再容易不過的事了。索居在華爾騰湖畔的梭羅說：「在 平和的日子，尋常中午，吃一些健康青翠的新鮮蔬菜，加上鹽，一個講究理性的人還能 希望什麼更多的食物呢？」人們缺少的往往不是必需的東西，而是奢侈的東西。 下列選項何者最接近上文意旨？', '["反對文明機巧", "反對物欲奢華", "提倡養生保健", "提倡理性科學"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:15+00:00", "source_pdf_sha1": "b69e8e076c7c", "answer_pdf_sha1": "15960b581ada", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "201", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "land", "db_exam_id": "land-agent"}'::jsonb, NULL),
  ('land-agent-moex-00142', 'land-agent', 'land-agent-moex-107-9a386a01', 'sub-land-agent-05', NULL, 'single_choice', '「傳說伯牙學琴的時候，苦練了三年仍學不精，他的老師帶他到蓬萊山下去留宿，讓他 一個人單獨地默聽海水洞汩崩折的聲音，這時山林窈冥，滄海無涯，群鳥悲號，天地愴 然。他忽然心開情移，邁上了琴藝的巔峰。」此種藝術境界，與下列選項何者最相近？', '["運斤成風，熟能生巧", "技進於道，萬化冥合", "探驪得珠，游刃有餘", "傳神阿堵，畫龍點睛"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:15+00:00", "source_pdf_sha1": "b69e8e076c7c", "answer_pdf_sha1": "15960b581ada", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "201", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "land", "db_exam_id": "land-agent"}'::jsonb, NULL),
  ('land-agent-moex-00143', 'land-agent', 'land-agent-moex-107-9a386a01', 'sub-land-agent-05', NULL, 'single_choice', '「同一個杯、同一種茶、同一種泡法，飲在不同的喉嚨裡，冷暖濃淡自知，完全是心證 功夫。有人喝茶是在喝一套精製而考究的手藝；有人握杯聞香，吐納清濁之氣；有人見 杯即乾，不事進德修業，專愛消化排泄；有人隨興，水是好水，壺是好壺，茶是好茶。 大化浪浪，半睡半醒，茶之一字，諸子百家都可以註解。」 依據上文，下列選項何者對文意說明最適當？', '["各自體會，適性自得", "如人飲水，冷暖自知", "講究火候，膾不厭細", "受人點滴，湧泉以報"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:15+00:00", "source_pdf_sha1": "b69e8e076c7c", "answer_pdf_sha1": "15960b581ada", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "201", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "land", "db_exam_id": "land-agent"}'::jsonb, NULL),
  ('land-agent-moex-00144', 'land-agent', 'land-agent-moex-107-9a386a01', 'sub-land-agent-05', NULL, 'single_choice', '「有人把寫作比作三種昆蟲做工，一種像螞蟻搬運東西，搬來搬去，都是別人的東西， 既不加工變造，又不點鐵成金，螞蟻搬物式是有時連他自己也沒搞清楚的，東抄西抄， 還硬說『天下文章一大抄』呢。一種像蜜蜂釀蜜，東採花、西採花，雖搜集自各方，卻 用一己的獨到工夫，把原有的蕊粉釀成了花蜜！還有一種像春蠶吐絲，當他吃足了桑葉， 然後不眠不休，心無旁鶩，只管自顧自地吐出柔絲錦緞來，嘔出來的早不是粗硬的桑葉， 而是精美的心血。」 根據上文，作者想強調的意旨為：', '["大量收集、引用材料是寫作的基本工夫", "春蠶吐絲比蜜蜂釀蜜式的創作更勝一籌", "寫作方法眾多，唯勤讀書方能下筆如神", "寫作著重作者自我的體會、消化與創造"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:15+00:00", "source_pdf_sha1": "b69e8e076c7c", "answer_pdf_sha1": "15960b581ada", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "201", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "land", "db_exam_id": "land-agent"}'::jsonb, NULL),
  ('land-agent-moex-00145', 'land-agent', 'land-agent-moex-107-9a386a01', 'sub-land-agent-05', NULL, 'single_choice', '「最近，老鼠村附近來了一隻大貓，於是老鼠們召開緊急會議商量對策。長老說：『我 們應該想個法子，在貓來以前發現牠，以便事先躲起來。』於是有隻老鼠想出一個好方 法，就是在貓的脖子綁上一顆鈴鐺，只要聽到鈴鐺的聲音，老鼠們就能迅速逃走。但是 當大家進一步討論誰去『給貓繫鈴鐺』的時候，卻沒有一隻老鼠願意做這件事。」 下列選項，最符合老鼠作為的是：', '["知易行難", "同舟共濟", "當仁不讓", "困心衡慮"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:15+00:00", "source_pdf_sha1": "b69e8e076c7c", "answer_pdf_sha1": "15960b581ada", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "201", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "land", "db_exam_id": "land-agent"}'::jsonb, NULL)
